#!/usr/bin/env node

// src/cli.ts
import { spawn, spawnSync } from "child_process";
import {
  writeFileSync,
  readFileSync,
  existsSync,
  mkdirSync,
  readdirSync,
  statSync
} from "fs";
import { basename, join } from "path";
import { homedir } from "os";
var RESET = "\x1B[0m";
